#include<bits/stdc++.h>
using namespace std;
const int N=1e6+10;
int n,m;
struct two_sat
{
    int low[N*2],dfn[N*2],dfncnt,scccnt,color[N*2];
    bool instk[N*2];
    vector<int> mp[N*2];
    stack<int> stk;
    void add(int x,int y)
    {
        mp[x].push_back(y);
    }
    void add(int i,int a,int j,int b)
    {
        mp[i+n*(a&1)].push_back(j+n*(b^1));
        mp[j+n*(b&1)].push_back(i+n*(a^1));
    }
    void tarjan(int x)
    {
        low[x]=dfn[x]=++dfncnt;
        stk.push(x);
        instk[x]=1;
        for(int v:mp[x])
        {
            if(!dfn[v])
            {
                tarjan(v);
                low[x]=min(low[x],low[v]);
            }
            else if(instk[v])
            {
                low[x]=min(low[x],dfn[v]);
            }
        }
        if(low[x]==dfn[x])
        {
            scccnt++;
            int top;
            do
            {
                top=stk.top();
                stk.pop();
                color[top]=scccnt;
                instk[top]=0;
            }while(top!=x);
        }
    }
    void solve()
    {
        for(int i=1;i<=(n<<1);i++)
        {
            if(!dfn[i])
            {
                tarjan(i);
            }
        }
    }
    bool possible()
    {
        for(int i=1;i<=n;i++)
        {
            if(color[i]==color[i+n])
            {
                return false;
            }
        }
        return true;
    }
    bool getans(int x)
    {
        return color[x]>color[x+n];
    }
}_2sat;
int main()
{
    scanf("%d%d",&n,&m);
    for(int I=1;I<=m;I++)
    {
        int i,a,j,b;
        scanf("%d%d%d%d",&i,&a,&j,&b);
        _2sat.add(i,a,j,b);
    }
    _2sat.solve();
    if(_2sat.possible())
    {
        printf("POSSIBLE\n");
        for(int i=1;i<=n;i++)
        {
            printf("%d ",1-(int)(_2sat.getans(i)));
        }
    }
    else
    {
        printf("IMPOSSIBLE");
    }
    return 0;
}
